import{o as a,c as e,a as s}from"./app.4ac67823.js";const t='{"title":"Analysis","description":"","frontmatter":{},"headers":[{"level":2,"title":"What\'s the analysis?","slug":"what-s-the-analysis"},{"level":2,"title":"Parts parsing to database","slug":"parts-parsing-to-database"}],"relativePath":"analysis.md","lastUpdated":1631124587454}',i={},n=[s('<h1 id="analysis"><a class="header-anchor" href="#analysis" aria-hidden="true">#</a> Analysis</h1><p><div class="table-of-contents"><ul><li><a href="#what-s-the-analysis">What&#39;s the analysis?</a></li><li><a href="#parts-parsing-to-database">Parts parsing to database</a></li></ul></div></p><h2 id="what-s-the-analysis"><a class="header-anchor" href="#what-s-the-analysis" aria-hidden="true">#</a> What&#39;s the analysis?</h2><p>The &quot;analysis&quot; builds the information needed for the panel viewer based on the uploaded files. The following are the main steps:</p><ul><li><p>If there are full project IFCs, a splitting process is accomplished. Each unique panel will result in a new IFC file. Those files can be downloaded.</p></li><li><p>The system collects all the drawings, details, docs, and panel IFCs (discarding full project IFCs).</p></li><li><p>A list of design names is built based on IFC filenames and drawings filenames.</p></li><li><p>All the docs are linked to the design, so they are always available.</p></li><li><p>Drawings are scanned to find detail names. Found detail names are linked to the design.</p></li><li><p>IFCs are scanned looking for detail names. Found names are linked to the design.</p></li><li><p>IFC geometry is analyzed to find rotation&amp;traslation matrices (orientation of the panel in the world coordinates system).</p></li><li><p>IFC parts are parsed to the main parts database.</p></li></ul><h2 id="parts-parsing-to-database"><a class="header-anchor" href="#parts-parsing-to-database" aria-hidden="true">#</a> Parts parsing to database</h2><p>Each part of the IFC will be analyzed, generating drawings and metadata which is saved in the database. This database table will bring fast access to the information when the user clicks on a part in the 3D viewer.</p><p>Drawings are only generated for &quot;wood&quot; and &quot;plate&quot; elements. So, if you don&#39;t have a good IFC Parsing Setup, you may find your panel with some missing drawings.</p>',8)];i.render=function(s,t,i,l,r,d){return a(),e("div",null,n)};export{t as __pageData,i as default};
